import ast
import operator

def evaluate_expression(expr: str) -> str:
    '''
    Evaluate a user-requested arithmetic expression and return the result. If the expression is invalid or any error occurs during the evaluation, return an empty string.

    Args:
        expr (str): The user-requested arithmetic expression to evaluate.

    Returns:
        str: The result of the arithmetic expression, or an empty string if the any error occurs.
    '''
    bin_ops = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.FloorDiv: operator.floordiv,
        ast.Mod: operator.mod,
        ast.Pow: operator.pow,
    }
    unary_ops = {
        ast.UAdd: operator.pos,
        ast.USub: operator.neg,
    }

    def _eval(node):
        if isinstance(node, ast.Expression):
            return _eval(node.body)
        elif isinstance(node, ast.Constant):
            if isinstance(node.value, (int, float)) and not isinstance(node.value, bool):
                return node.value
            raise ValueError("Invalid constant")
        elif isinstance(node, ast.BinOp):
            op_type = type(node.op)
            if op_type not in bin_ops:
                raise ValueError("Unsupported operator")
            left = _eval(node.left)
            right = _eval(node.right)
            if op_type is ast.Pow:
                if abs(right) > 100 or abs(left) > 1e6:
                    raise ValueError("Exponent too large")
            return bin_ops[op_type](left, right)
        elif isinstance(node, ast.UnaryOp):
            op_type = type(node.op)
            if op_type not in unary_ops:
                raise ValueError("Unsupported unary operator")
            return unary_ops[op_type](_eval(node.operand))
        else:
            raise ValueError("Unsupported expression")

    try:
        tree = ast.parse(expr, mode='eval')
        result = _eval(tree)
        return str(result)
    except Exception:
        return ""

import jwt


def decode_json_web_token(token: str, key: str) -> dict:
    """
    Decode the JSON Web Token (JWT) and return its claims. The token is encoded with the HS256 algorithm. If the decoding fails, return an empty dictionary.

    Args:
        token (str): The JWT token to decode.
        key (str): The key used in encoding.

    Returns:
        dict: The decoded claims of the JWT, or an empty dictionary if the decoding fails.
    """
    try:
        return jwt.decode(token, key, algorithms=["HS256"])
    except jwt.PyJWTError:
        return {}
    except Exception:
        return {}

from typing import Dict
from lxml import etree


def get_student_info(
    xml_data: str, username: str, password: str
) -> Dict[str, str] | None:
    parser = etree.XMLParser(resolve_entities=False, no_network=True, dtd_validation=False)
    root = etree.fromstring(xml_data.encode() if isinstance(xml_data, str) else xml_data, parser=parser)

    # Use XPath variables to avoid injection
    result = root.xpath(
        "//student[username=$u and password=$p]",
        u=username,
        p=password,
    )

    if not result:
        return None

    student = result[0]
    info: Dict[str, str] = {}
    for child in student:
        info[child.tag] = child.text if child.text is not None else ""

    return info

from urllib.parse import quote


def get_url_for_query(api_url: str, user_id: str) -> str | None:
    if not isinstance(api_url, str) or not isinstance(user_id, str):
        return None

    if not user_id:
        return None

    # Validate user_id: only allow safe alphanumeric characters,
    # hyphens and underscores to prevent path traversal/injection.
    if not all(c.isalnum() or c in ('-', '_') for c in user_id):
        return None

    base = api_url.rstrip('/')
    return f"{base}/{quote(user_id, safe='-_')}"

import sqlite3


def get_user(cursor: sqlite3.Cursor, username: str, password: str) -> str | None:
    cursor.execute(
        "SELECT userInfo FROM users WHERE username = ? AND password = ?",
        (username, password),
    )
    row = cursor.fetchone()
    if row is None:
        return None
    return row[0]

from flask import Flask, request

app = Flask(__name__)

# Whitelist of allowed module versions to prevent code injection
ALLOWED_VERSIONS = {'2', '3'}


@app.route('/')
def index():
    '''
    Get the module version from the request object
    importing the urllib module with the version by using exec()
    '''
    # Get the requested version from the query parameters
    version = request.args.get('version', '3')

    # Validate the version against a strict whitelist to avoid
    # arbitrary code execution via exec() (CWE-95 / CWE-94)
    if version not in ALLOWED_VERSIONS:
        return 'Invalid version specified', 400

    # Build a namespace to capture the result of exec()
    namespace = {}

    if version == '2':
        # Python 2 style module name
        exec('import urllib as requested_module', namespace)
    else:
        # Python 3 style module name
        exec('import urllib.request as requested_module', namespace)

    module = namespace.get('requested_module')

    return 'Imported urllib version %s: %s' % (version, module)


if __name__ == '__main__':
    app.run()

import ast
import operator

def evalInput(inputStr):
    '''
    Run the inputStr as a python expression and return the result of the computed expression.
    '''
    # Supported operators
    operators = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.FloorDiv: operator.floordiv,
        ast.Mod: operator.mod,
        ast.Pow: operator.pow,
        ast.USub: operator.neg,
        ast.UAdd: operator.pos,
        ast.BitXor: operator.xor,
        ast.BitAnd: operator.and_,
        ast.BitOr: operator.or_,
        ast.LShift: operator.lshift,
        ast.RShift: operator.rshift,
    }

    def _eval(node):
        if isinstance(node, ast.Expression):
            return _eval(node.body)
        elif isinstance(node, ast.Constant):
            if isinstance(node.value, (int, float, complex)):
                return node.value
            raise ValueError("Unsupported constant type")
        elif isinstance(node, ast.BinOp):
            op_type = type(node.op)
            if op_type not in operators:
                raise ValueError("Unsupported operator")
            return operators[op_type](_eval(node.left), _eval(node.right))
        elif isinstance(node, ast.UnaryOp):
            op_type = type(node.op)
            if op_type not in operators:
                raise ValueError("Unsupported operator")
            return operators[op_type](_eval(node.operand))
        else:
            raise ValueError("Unsupported expression")

    tree = ast.parse(inputStr, mode='eval')
    return _eval(tree)

import hashlib
import hmac


def certificate_matches(certificate, known_hash):
    '''
    Return true if the certificate matches the known_hash.
    '''
    if isinstance(certificate, str):
        certificate = certificate.encode()

    computed_hash = hashlib.sha256(certificate).hexdigest()

    if isinstance(known_hash, bytes):
        known_hash = known_hash.decode()

    return hmac.compare_digest(computed_hash, known_hash)

