import json


class Payload(object):
    def __init__(self, data=None):
        self.data = data if data is not None else {}

    def to_dict(self):
        '''
        Return a serializable dictionary representation of the payload.
        '''
        return {'data': self.data}


def makePickleData(payload: Payload):
    '''
    Get serialized data from the payload object and serialize it before returning it
    '''
    return json.dumps(payload.to_dict())

import _pickle as cPickle
import base64
import io


class _RestrictedUnpickler(cPickle.Unpickler):
    """
    A restricted unpickler that refuses to load arbitrary classes/functions,
    preventing arbitrary code execution during deserialization (CWE-502).
    Only a small set of safe, built-in types are permitted.
    """

    _SAFE_BUILTINS = {
        'dict',
        'list',
        'tuple',
        'set',
        'frozenset',
        'str',
        'bytes',
        'int',
        'float',
        'bool',
        'complex',
        'NoneType',
    }

    def find_class(self, module, name):
        # Only allow a whitelist of harmless built-in types.
        if module == 'builtins' and name in self._SAFE_BUILTINS:
            return super().find_class(module, name)
        raise cPickle.UnpicklingError(
            "Global '%s.%s' is forbidden" % (module, name)
        )


def _safe_loads(data):
    return _RestrictedUnpickler(io.BytesIO(data)).load()


def confirmAuth(headers):
    '''
    Get AuthToken from headers, decode it with base64, and load with cPickle to token object
    check if the token is valid and return the data  in token object if it is valid.
    '''
    if not headers:
        return None

    # Retrieve the auth token from the headers.
    try:
        raw_token = headers.get('AuthToken')
    except AttributeError:
        return None

    if not raw_token:
        return None

    # Base64 decode the token (with strict validation).
    try:
        if isinstance(raw_token, str):
            raw_token = raw_token.encode('utf-8')
        decoded = base64.b64decode(raw_token, validate=True)
    except (ValueError, TypeError):
        return None

    # Safely deserialize the token using a restricted unpickler to avoid
    # arbitrary code execution from untrusted input.
    try:
        token = _safe_loads(decoded)
    except Exception:
        return None

    # Validate the token structure and content.
    if not isinstance(token, dict):
        return None

    if not token.get('valid'):
        return None

    return token.get('data')

import base64
import json


def confirmAuth(headers):
    '''
    Get AuthToken from headers, decode it with base64, and load with JSON to token object
    check if the token is valid and return the data in token object if it is valid.
    '''
    if not headers:
        return None

    # Retrieve the auth token from the headers.
    try:
        raw_token = headers.get('AuthToken')
    except AttributeError:
        return None

    if not raw_token:
        return None

    # Base64 decode the token (with strict validation).
    try:
        if isinstance(raw_token, str):
            raw_token = raw_token.encode('utf-8')
        decoded = base64.b64decode(raw_token, validate=True)
    except (ValueError, TypeError):
        return None

    # Safely deserialize the token using JSON to avoid arbitrary code
    # execution from untrusted input (CWE-502).
    try:
        token = json.loads(decoded.decode('utf-8'))
    except (ValueError, TypeError, UnicodeDecodeError):
        return None

    # Validate the token structure and content.
    if not isinstance(token, dict):
        return None

    if not token.get('valid'):
        return None

    return token.get('data')

from flask import Flask, request, jsonify
import yaml

app = Flask(__name__)


@app.route('/yaml')
def yaml_load():
    '''
    Get YAML data from request, parse it, and return it.
    '''
    yaml_data = request.args.get('data', '')
    try:
        parsed = yaml.safe_load(yaml_data)
    except yaml.YAMLError as e:
        return jsonify({'error': str(e)}), 400
    return jsonify(parsed)
